1	export type Cell = [row: number, col: number];
2	
3	const cellKey = (cell: Cell): string => `${cell[0]},${cell[1]}`;
4	
5	const cellFromKey = (key: string): Cell => key.split(",").map(Number) as Cell;
6	
7	const neighbors = (cell: Cell): Cell[] => {
8	  const [r, c] = cell;
9	  return [
10	    [r - 1, c - 1], [r - 1, c], [r - 1, c + 1],
11	    [r,     c - 1],             [r,     c + 1],
12	    [r + 1, c - 1], [r + 1, c], [r + 1, c + 1],
13	  ] as Cell[];
14	};
15	
16	export function nextGeneration(cells: Cell[]): Cell[] {
17	  const liveSet = new Set(cells.map(cellKey));
18	  const neighborCount = new Map<string, number>();
19	
20	  for (const cell of cells) {
21	    for (const n of neighbors(cell)) {
22	      const k = cellKey(n);
23	      neighborCount.set(k, (neighborCount.get(k) ?? 0) + 1);
24	    }
25	  }
26	
27	  const result: Cell[] = [];
28	  for (const [k, count] of neighborCount) {
29	    const isAlive = liveSet.has(k);
30	    const survives = isAlive && (count === 2 || count === 3);
31	    const isReborn = !isAlive && count === 3;
32	    if (survives || isReborn) {
33	      result.push(cellFromKey(k));
34	    }
35	  }
36	
37	  result.sort((a, b) => a[1] - b[1] || a[0] - b[0]);
38	  return result;
39	}
