1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should return empty array for single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should return empty array for two live cells (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a block of four cells alive (still life)", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    expect(nextGeneration(block)).toEqual([[0, 0], [1, 0], [0, 1], [1, 1]]);
17	  });
18	  it("should bring a dead cell to life with exactly 3 live neighbors (reproduction)", () => {
19	    const gen0: [number, number][] = [[0, 0], [1, 0], [0, 1]];
20	    expect(nextGeneration(gen0)).toEqual([[0, 0], [1, 0], [0, 1], [1, 1]]);
21	  });
22	  it("should kill a live cell with more than 3 live neighbors (overpopulation)", () => {
23	    // 3x3 block: center cell (1,1) has 8 live neighbors -> dies from overpopulation
24	    const gen0: [number, number][] = [
25	      [0, 0], [1, 0], [2, 0],
26	      [0, 1], [1, 1], [2, 1],
27	      [0, 2], [1, 2], [2, 2],
28	    ];
29	    const result = nextGeneration(gen0);
30	    const hasCenter = result.some(([r, c]) => r === 1 && c === 1);
31	    expect(hasCenter).toBe(false);
32	  });
33	  it.todo("should transform a blinker to its next generation (oscillator)");
34	});
